class SeededRng {
  private s: number;
  constructor(seed: number) { this.s = seed; }
  next(): number {
    this.s = (this.s * 16807) % 2147483647;
    return (this.s - 1) / 2147483646;
  }
  jitter(amount: number): number { return (this.next() - 0.5) * 2 * amount; }
}

