export class VictimOutline extends BaseEffect {
  readonly name = 'victimOutline';
  private initialized = false;

  protected setup(): void {}

  private initOutlines(width: number, height: number): void {
    if (this.initialized) return;
    this.initialized = true;

    const color     = resolveColor(this.config.color ?? '#ffffff', this.palette);
    const alpha     = this.config.alpha     ?? 0.88;
    const scale     = this.config.scale     ?? 1.5;
    const lineWidth = this.config.lineWidth ?? 5;
    const seed      = this.config.seed      ?? 0;

    const cx = this.config.x != null
      ? (this.config.x as number) * width
      : width  * 0.5;
    const cy = this.config.y != null
      ? (this.config.y as number) * height
      : height * 0.5;
    const rotation = this.config.rotation != null
      ? this.config.rotation as number
      : 0;

    const wrapper = new PIXI.Container();
    wrapper.x = cx;
    wrapper.y = cy;
    wrapper.rotation = rotation;
    wrapper.alpha = alpha;

    this.drawOutline(wrapper, scale, color, lineWidth, new SeededRng(seed));
    this.container.addChild(wrapper);
  }

  private drawOutline(
    container: PIXI.Container,
    s: number,
    color: string,
    lineWidth: number,
    rng: SeededRng,
  ): void {
    const lw    = lineWidth;
    const jAmt  = lw * s * 0.45;
    const stroke = (width: number, alpha: number) => ({
      color, width, alpha,
      cap: 'round'  as const,
      join: 'round' as const,
      miterLimit: 10,
    });

    // 主笔（带粉笔随机抖动）
    const g1 = new PIXI.Graphics();
    for (const contour of VICTIM_CONTOURS) {
      const jittered = contour.map(([x, y]): [number, number] =>
        [x * s + rng.jitter(jAmt), y * s + rng.jitter(jAmt)]);
      g1.moveTo(jittered[0][0], jittered[0][1]);
      for (let i = 1; i < jittered.length; i++) g1.lineTo(jittered[i][0], jittered[i][1]);
      g1.closePath();
    }
    g1.stroke(stroke(lw * s, 1.0));

    // 晕散层（更大抖动，细线半透明）
    const g2 = new PIXI.Graphics();
    for (const contour of VICTIM_CONTOURS) {
      const jittered = contour.map(([x, y]): [number, number] =>
        [x * s + rng.jitter(jAmt * 2.2), y * s + rng.jitter(jAmt * 2.2)]);
      g2.moveTo(jittered[0][0], jittered[0][1]);
      for (let i = 1; i < jittered.length; i++) g2.lineTo(jittered[i][0], jittered[i][1]);
      g2.closePath();
    }
    g2.stroke(stroke(lw * s * 0.38, 0.28));

    container.addChild(g1, g2);
  }

  update(ctx: UpdateContext): void {
    this.initOutlines(ctx.screenWidth, ctx.screenHeight);
  }
}
